import { useState } from "react";
import styled from "styled-components";
import Form from "./Form";

import backgroundImage from '../../img/ContactForm/bg.jpg'

const ContactForm = ({ id }) => {
  const [isEmailSent, setIsEmailSent] = useState(false)
  console.log(isEmailSent)

  return (
    <ContactFormContainer id={id}>
      <div>
        <h3> Do you want to ask me a question? </h3>
        <h4> Use a contact form or other options listed below </h4>
      </div>
      {
        !isEmailSent
          ? <Form setIsEmailSent={setIsEmailSent} />
          : <SuccessInformation> Your email has been successfully sent, I will try to answer your question as fast as possible. </SuccessInformation>
      }
    </ContactFormContainer>
  )
}

const ContactFormContainer = styled.section`
  padding: 5em 0;
  background-size: cover;
  color: white;
  display: flex;
  flex-direction: column;
  justify-content: space-around;
  align-items: center;
  row-gap: 1em;
  box-shadow: 0px 0px 2px black;
  position: relative;
  min-height: 30em;
  
  &:before {
    content: "";
    position: absolute;
    z-index: -1;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    background: url(${backgroundImage}) center center no-repeat;
    background-size: cover;
    filter: brightness(0.2) blur(4px);
    box-shadow: 0px 0px 1px black;
  }

  & h3 {
    margin: 0;
    font-size: 2em;
    text-align: center;
  }

  & h4 {
    margin: 0;
    font-size: 1em;
    font-weight: 400;
    text-align: center;
  }
`

const SuccessInformation = styled.span`
  color: green;
`

export default ContactForm
